1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty array for single live cell (dies of underpopulation)", () => {
9	    const singleCell: Cell[] = [{ x: 0, y: 0 }];
10	    expect(nextGeneration(singleCell)).toEqual([]);
11	  });
12	  it("should return empty array when all cells die of underpopulation", () => {
13	    const twoCells: Cell[] = [{ x: 0, y: 0 }, { x: 1, y: 0 }];
14	    expect(nextGeneration(twoCells)).toEqual([]);
15	  });
16	  it("should keep cells alive when they have exactly 2 live neighbors (survival)", () => {
17	    const cells: Cell[] = [{ x: 0, y: 0 }, { x: 1, y: 0 }, { x: 2, y: 0 }];
18	    const result = nextGeneration(cells);
19	    expect(result).toContainEqual({ x: 1, y: 0 });
20	  });
21	  it.todo("should keep cells alive when they have exactly 3 live neighbors (survival)");
22	  it.todo("should kill live cell with more than 3 live neighbors (overpopulation)");
23	  it.todo("should bring dead cell to life with exactly 3 live neighbors (reproduction)");
24	  it.todo("should keep block (2x2) pattern unchanged as a still life");
25	  it.todo("should evolve blinker from vertical to horizontal in one generation");
26	});
