1	export type Cell = { x: number; y: number };
2	
3	const countNeighbors = (cell: Cell, liveCells: Cell[]): number =>
4	  liveCells.filter(
5	    (candidate) =>
6	      Math.abs(candidate.x - cell.x) <= 1 &&
7	      Math.abs(candidate.y - cell.y) <= 1 &&
8	      !(candidate.x === cell.x && candidate.y === cell.y)
9	  ).length;
10	
11	export const nextGeneration = (liveCells: Cell[]): Cell[] =>
12	  liveCells.filter((cell) => {
13	    const neighbors = countNeighbors(cell, liveCells);
14	    return neighbors === 2 || neighbors === 3;
15	  });
